def evaluate(req):
    if not req["identity_verified"]:
        return "DENY (identity_not_verified)"
    if not req["device_compliant"]:
        return "DENY (device_not_compliant)"
    if req["resource_sensitivity"] == "high" and not req["mfa"]:
        return "DENY (mfa_required)"
    return "ALLOW"
